const now = new Date();
const day = now.getDay();
if (day === 0 || day === 6) return [];
return [{ json: { hour: now.getHours(), day } }];

const items = $input.all();
const now = new Date();
const hour = now.getHours();

// Если запуск ручной — берём все блоги без фильтрации
const isManual = $execution.mode === 'manual';
if (isManual) {
  return items.map(item => ({ json: item.json }));
}

function hash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h) + str.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h);
}

const dateKey = `${now.getFullYear()}-${now.getMonth()}-${now.getDate()}`;
const windows = [[9,10,11],[12,13,14,15],[17,18,19,20]];

const filtered = items.filter(item => {
  const blog = item.json;
  const h = hash(`${dateKey}-${blog.id}`);
  const window = windows[h % 3];
  const publishHour = window[Math.floor(h / 3) % window.length];
  return hour === publishHour;
});

if (filtered.length === 0) return [];
return filtered.map(item => ({ json: item.json }));

const blog = $json;

const result = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://172.17.0.1:8000/api/ai/generate-post',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ blog_id: blog.id, prompt: '' }),
  ignoreHttpStatusErrors: true
});

const post = typeof result === 'string' ? JSON.parse(result) : result;
if (!post.title || !post.content) {
  throw new Error('Bad post response: ' + JSON.stringify(post).slice(0, 200));
}

return [{ json: { blog, ...post } }];

const d = $json;

// Делим контент на абзацы
const paragraphs = d.content.split(/\n\n+/).filter(p => p.trim().length > 50);
const total = paragraphs.length;

// Выбираем 2-3 позиции: примерно после 1/3 и 2/3 текста
const positions = [];
if (total >= 4) {
  positions.push(Math.floor(total * 0.33));
  positions.push(Math.floor(total * 0.66));
  if (total >= 7) positions.push(Math.floor(total * 0.85));
}

// Для каждой позиции — берём абзац и генерируем поисковый запрос
// Используем сам текст абзаца как контекст
const spots = positions.map((paraIdx, i) => {
  const context = paragraphs[paraIdx] || '';
  // Берём первые 150 символов абзаца как основу для запроса
  const snippet = context.slice(0, 150).replace(/[^а-яёa-z0-9\s]/gi, ' ').trim();
  // Добавляем нишу для релевантности
  const query = `${d.blog.niche} ${snippet}`.slice(0, 100);
  return { paraIdx, query };
});

return [{ json: { ...d, spots, paragraphs } }];

const d = $json;
const spots = d.spots || [];
const paragraphs = d.paragraphs || d.content.split(/\n\n+/);

// Для каждого спота ищем фото
const photosMap = {};

for (const spot of spots) {
  const query = encodeURIComponent(spot.query);
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.unsplash.com/photos/random?query=${query}&orientation=landscape&content_filter=high`,
      headers: { 'Authorization': `Client-ID ${$env.UNSPLASH_ACCESS_KEY}` },
      ignoreHttpStatusErrors: true
    });
    if (resp && resp.urls) {
      photosMap[spot.paraIdx] = {
        url:        resp.urls.regular,
        author:     resp.user?.name || '',
        authorUrl:  resp.user?.links?.html || '',
      };
    }
  } catch(e) {
    console.log('Unsplash error for spot', spot.paraIdx, e.message);
  }
  // Небольшая пауза чтобы не спамить API
  await new Promise(r => setTimeout(r, 300));
}

// Вставляем фото в нужные места контента
// Формат: специальный маркер [[PHOTO:url|author|authorUrl]] между абзацами
const result = [];
for (let i = 0; i < paragraphs.length; i++) {
  result.push(paragraphs[i]);
  if (photosMap[i]) {
    const p = photosMap[i];
    result.push(`[[PHOTO:${p.url}|${p.author}|${p.authorUrl}]]`);
  }
}

const contentWithPhotos = result.join('\n\n');

return [{ json: {
  blog:            d.blog,
  title:           d.title,
  content:         d.content,           // оригинал для Telegram
  contentWithPhotos,                    // с фото для сайта
  category:        d.category,
  excerpt:         d.excerpt,
  photoCount:      Object.keys(photosMap).length,
} }];

const d = $json;

// Сохраняем пост с фото-маркерами (main.py распарсит их при рендере)
await this.helpers.httpRequest({
  method: 'POST',
  url: `http://172.17.0.1:8000/api/blogs/${d.blog.id}/posts`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    title:    d.title,
    content:  d.contentWithPhotos,
    category: d.category || d.blog.niche,
    excerpt:  d.excerpt  || '',
  }),
  ignoreHttpStatusErrors: true
});

// Telegram — оригинальный контент без фото, с разбивкой
if (d.blog.telegram_channel) {
  const MAX = 4000;
  function splitText(text, maxLen) {
    const parts = [];
    const paragraphs = text.split(/\n\n+/);
    let current = '';
    for (const para of paragraphs) {
      const candidate = current ? current + '\n\n' + para : para;
      if (candidate.length <= maxLen) {
        current = candidate;
      } else {
        if (current) parts.push(current.trim());
        if (para.length > maxLen) {
          const sentences = para.match(/[^.!?]+[.!?]+/g) || [para];
          let chunk = '';
          for (const s of sentences) {
            if ((chunk + s).length <= maxLen) { chunk += s; }
            else { if (chunk) parts.push(chunk.trim()); chunk = s; }
          }
          if (chunk) current = chunk.trim();
        } else { current = para; }
      }
    }
    if (current) parts.push(current.trim());
    return parts;
  }

  const parts = splitText(d.content, MAX);
  const total = parts.length;
  for (let i = 0; i < total; i++) {
    const suffix = total > 1 ? `\n\n— ${i+1}/${total}` : '';
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${$env.TELEGRAM_BOT_TOKEN}/sendMessage`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id: d.blog.telegram_channel, text: parts[i] + suffix }),
      ignoreHttpStatusErrors: true
    });
    if (i < total - 1) await new Promise(r => setTimeout(r, 500));
  }
}

return [{ json: { status: 'published', blog: d.blog.id, title: d.title } }];
